import { useState } from 'react';
import { NavLink, Outlet, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { LayoutDashboard, Receipt, CreditCard, BarChart3, Settings, LogOut, Sun, Moon, Menu, X, ChevronRight, Bell } from 'lucide-react';
import useAuthStore from '../store/authStore';
import useUIStore from '../store/uiStore';
import toast from 'react-hot-toast';

const navItems = [
  { path: '/', icon: LayoutDashboard, label: 'Dashboard' },
  { path: '/expenses', icon: Receipt, label: 'Expenses' },
  { path: '/subscriptions', icon: CreditCard, label: 'Subscriptions' },
  { path: '/analytics', icon: BarChart3, label: 'Analytics' },
  { path: '/settings', icon: Settings, label: 'Settings' },
];

export default function Layout() {
  const { user, logout } = useAuthStore();
  const { theme, toggleTheme, sidebarOpen, toggleSidebar } = useUIStore();
  const navigate = useNavigate();
  const [mobileOpen, setMobileOpen] = useState(false);

  const handleLogout = () => {
    logout();
    toast.success('Logged out successfully');
    navigate('/login');
  };

  const initials = user?.name?.split(' ').map(n => n[0]).join('').toUpperCase() || 'U';

  const Sidebar = ({ mobile = false }) => (
    <div style={{
      width: mobile ? '280px' : sidebarOpen ? '240px' : '72px',
      height: '100vh',
      background: 'var(--bg-secondary)',
      borderRight: '1px solid var(--border)',
      display: 'flex',
      flexDirection: 'column',
      padding: '20px 12px',
      transition: 'width 0.3s ease',
      overflow: 'hidden',
      flexShrink: 0,
    }}>
      {/* Logo */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '8px 6px', marginBottom: '28px' }}>
        <div style={{ width: '36px', height: '36px', borderRadius: '10px', background: 'linear-gradient(135deg, #6366f1, #8b5cf6)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '18px', flexShrink: 0 }}>≡ƒÆ╣</div>
        {(sidebarOpen || mobile) && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ overflow: 'hidden' }}>
            <div style={{ fontFamily: 'Space Grotesk', fontWeight: '800', fontSize: '16px', whiteSpace: 'nowrap' }} className="gradient-text">FinTracker</div>
            <div style={{ fontSize: '11px', color: 'var(--text-muted)', whiteSpace: 'nowrap' }}>Pro Edition</div>
          </motion.div>
        )}
      </div>

      {/* Nav Items */}
      <nav style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '4px' }}>
        {navItems.map(({ path, icon: Icon, label }) => (
          <NavLink key={path} to={path} end={path === '/'} onClick={() => mobile && setMobileOpen(false)}
            className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
            style={{ justifyContent: sidebarOpen || mobile ? 'flex-start' : 'center' }}
          >
            <Icon size={18} style={{ flexShrink: 0 }} />
            {(sidebarOpen || mobile) && <span style={{ whiteSpace: 'nowrap' }}>{label}</span>}
          </NavLink>
        ))}
      </nav>

      {/* Bottom section */}
      <div style={{ borderTop: '1px solid var(--border)', paddingTop: '16px', display: 'flex', flexDirection: 'column', gap: '4px' }}>
        {/* User avatar */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '10px 8px', borderRadius: '10px', marginBottom: '4px' }}>
          <div style={{ width: '32px', height: '32px', borderRadius: '50%', background: 'linear-gradient(135deg, #6366f1, #ec4899)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '13px', fontWeight: '700', color: 'white', flexShrink: 0 }}>
            {initials}
          </div>
          {(sidebarOpen || mobile) && (
            <div style={{ overflow: 'hidden' }}>
              <div style={{ fontSize: '13px', fontWeight: '600', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{user?.name}</div>
              <div style={{ fontSize: '11px', color: 'var(--text-muted)', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{user?.email}</div>
            </div>
          )}
        </div>

        <button onClick={handleLogout} className="nav-item" style={{ background: 'none', border: 'none', width: '100%', textAlign: 'left', justifyContent: sidebarOpen || mobile ? 'flex-start' : 'center', color: '#ef4444' }}>
          <LogOut size={18} />
          {(sidebarOpen || mobile) && <span>Logout</span>}
        </button>
      </div>
    </div>
  );

  return (
    <div style={{ display: 'flex', height: '100vh', overflow: 'hidden', background: 'var(--bg-primary)' }}>
      <div className="animated-bg" />

      {/* Desktop Sidebar */}
      <div className="hidden lg:block">
        <Sidebar />
      </div>

      {/* Mobile Sidebar */}
      <AnimatePresence>
        {mobileOpen && (
          <>
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setMobileOpen(false)}
              style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)', zIndex: 40, backdropFilter: 'blur(4px)' }} className="lg:hidden" />
            <motion.div initial={{ x: -280 }} animate={{ x: 0 }} exit={{ x: -280 }} transition={{ type: 'spring', damping: 30 }}
              style={{ position: 'fixed', left: 0, top: 0, zIndex: 50 }} className="lg:hidden">
              <Sidebar mobile />
            </motion.div>
          </>
        )}
      </AnimatePresence>

      {/* Main content */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Top bar */}
        <header style={{ height: '64px', background: 'var(--bg-secondary)', borderBottom: '1px solid var(--border)', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 24px', flexShrink: 0 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <button onClick={() => setMobileOpen(true)} className="lg:hidden" style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-primary)', padding: '4px' }}>
              <Menu size={22} />
            </button>
            <button onClick={toggleSidebar} className="hidden lg:block" style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-secondary)', padding: '4px' }}>
              <Menu size={20} />
            </button>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <button onClick={toggleTheme} style={{ width: '36px', height: '36px', borderRadius: '8px', background: 'var(--bg-card)', border: '1px solid var(--border)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-secondary)' }}>
              {theme === 'dark' ? <Sun size={16} /> : <Moon size={16} />}
            </button>
            <button style={{ width: '36px', height: '36px', borderRadius: '8px', background: 'var(--bg-card)', border: '1px solid var(--border)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-secondary)', position: 'relative' }}>
              <Bell size={16} />
              <span style={{ position: 'absolute', top: '6px', right: '6px', width: '7px', height: '7px', borderRadius: '50%', background: '#ef4444' }} />
            </button>
            <div style={{ width: '36px', height: '36px', borderRadius: '50%', background: 'linear-gradient(135deg, #6366f1, #ec4899)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '13px', fontWeight: '700', color: 'white', cursor: 'pointer' }}>
              {initials}
            </div>
          </div>
        </header>

        {/* Page content */}
        <main style={{ flex: 1, overflow: 'auto', padding: '24px' }}>
          <Outlet />
        </main>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  LineChart, Line, PieChart, Pie, Cell, Legend, AreaChart, Area
} from 'recharts';
import api from '../lib/api';
import useAuthStore from '../store/authStore';
import { formatCurrency, CATEGORY_COLORS, CATEGORY_ICONS } from '../utils/helpers';
import toast from 'react-hot-toast';

const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

const CustomTooltip = ({ active, payload, label, currency }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '10px', padding: '12px 16px' }}>
      <p style={{ fontSize: '13px', fontWeight: '700', marginBottom: '4px' }}>{label}</p>
      {payload.map((p, i) => (
        <p key={i} style={{ fontSize: '13px', color: p.color || 'var(--accent-light)' }}>
          {p.name}: {formatCurrency(p.value, currency)}
        </p>
      ))}
    </div>
  );
};

export default function Analytics() {
  const [data, setData] = useState(null);
  const [subData, setSubData] = useState([]);
  const [year, setYear] = useState(new Date().getFullYear());
  const [loading, setLoading] = useState(true);
  const { user } = useAuthStore();
  const currency = user?.currency || 'INR';

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const [expRes, subRes] = await Promise.all([
          api.get('/expenses/analytics', { params: { year } }),
          api.get('/subscriptions', { params: { status: 'active' } }),
        ]);
        setData(expRes.data);
        setSubData(subRes.data.subscriptions);
      } catch { toast.error('Failed to load analytics'); }
      finally { setLoading(false); }
    };
    load();
  }, [year]);

  // Build monthly array for chart
  const monthlyChart = MONTHS.map((month, i) => {
    const found = data?.monthlySpending?.find(m => m._id.month === i + 1);
    return { month, amount: found?.total || 0, count: found?.count || 0 };
  });

  const categoryChart = data?.categoryBreakdown?.map(c => ({
    name: c._id, value: c.total, color: CATEGORY_COLORS[c._id] || '#6366f1', icon: CATEGORY_ICONS[c._id]
  })) || [];

  const subByCategory = Object.values(
    subData.reduce((acc, s) => {
      if (!acc[s.category]) acc[s.category] = { name: s.category, value: 0, count: 0 };
      const monthly = s.billingCycle === 'yearly' ? s.amount / 12 : s.billingCycle === 'quarterly' ? s.amount / 3 : s.billingCycle === 'weekly' ? s.amount * 4 : s.amount;
      acc[s.category].value += monthly;
      acc[s.category].count += 1;
      return acc;
    }, {})
  );

  const totalSpend = data?.categoryBreakdown?.reduce((a, c) => a + c.total, 0) || 0;

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '400px', flexDirection: 'column', gap: '16px' }}>
      <div className="spinner" /><p style={{ color: 'var(--text-muted)', fontSize: '14px' }}>Crunching numbers...</p>
    </div>
  );

  return (
    <div style={{ maxWidth: '1400px' }}>
      <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '28px', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h1 style={{ fontSize: '26px', fontWeight: '800', fontFamily: 'Space Grotesk', marginBottom: '4px' }}>≡ƒôè Analytics</h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: '14px' }}>Deep insights into your financial patterns</p>
        </div>
        <select className="input-field" style={{ width: 'auto' }} value={year} onChange={e => setYear(e.target.value)}>
          {[2023, 2024, 2025, 2026].map(y => <option key={y} value={y}>{y}</option>)}
        </select>
      </motion.div>

      {/* Total spend card */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '16px', marginBottom: '24px' }}>
        {[
          { label: 'Total Spent', value: formatCurrency(totalSpend, currency), icon: '≡ƒÆ░', sub: `in ${year}` },
          { label: 'Avg Monthly', value: formatCurrency(totalSpend / 12, currency), icon: '≡ƒôà', sub: 'per month' },
          { label: 'Categories', value: categoryChart.length, icon: '≡ƒÅ╖∩╕Å', sub: 'active categories' },
          { label: 'Monthly Sub Cost', value: formatCurrency(subData.reduce((a, s) => a + (s.billingCycle === 'monthly' ? s.amount : s.billingCycle === 'yearly' ? s.amount / 12 : s.billingCycle === 'quarterly' ? s.amount / 3 : s.amount * 4), 0), currency), icon: '≡ƒöä', sub: 'recurring/month' },
        ].map((s, i) => (
          <motion.div key={i} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}
            className="stat-card" style={{ padding: '20px' }}>
            <div style={{ fontSize: '28px', marginBottom: '8px' }}>{s.icon}</div>
            <div style={{ fontSize: '22px', fontWeight: '800', fontFamily: 'Space Grotesk', marginBottom: '4px' }}>{s.value}</div>
            <div style={{ fontSize: '13px', fontWeight: '600', color: 'var(--text-secondary)', marginBottom: '2px' }}>{s.label}</div>
            <div style={{ fontSize: '11px', color: 'var(--text-muted)' }}>{s.sub}</div>
          </motion.div>
        ))}
      </div>

      {/* Bar chart - Monthly Spending */}
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}
        className="glass-card" style={{ padding: '24px', marginBottom: '20px' }}>
        <h3 style={{ fontSize: '16px', fontWeight: '700', marginBottom: '20px' }}>Monthly Spending Overview</h3>
        <ResponsiveContainer width="100%" height={280}>
          <AreaChart data={monthlyChart}>
            <defs>
              <linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#6366f1" stopOpacity={0.3} />
                <stop offset="95%" stopColor="#6366f1" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" />
            <XAxis dataKey="month" tick={{ fill: 'var(--text-muted)', fontSize: 12 }} axisLine={false} tickLine={false} />
            <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} tickFormatter={v => `Γé╣${(v / 1000).toFixed(0)}k`} />
            <Tooltip content={<CustomTooltip currency={currency} />} />
            <Area type="monotone" dataKey="amount" name="Spending" stroke="#6366f1" fill="url(#areaGrad)" strokeWidth={2.5} dot={{ fill: '#6366f1', r: 4 }} activeDot={{ r: 6 }} />
          </AreaChart>
        </ResponsiveContainer>
      </motion.div>

      {/* Category & Subscription charts */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: '20px' }}>
        {/* Category pie */}
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }}
          className="glass-card" style={{ padding: '24px' }}>
          <h3 style={{ fontSize: '16px', fontWeight: '700', marginBottom: '20px' }}>Category Distribution</h3>
          {categoryChart.length > 0 ? (
            <ResponsiveContainer width="100%" height={280}>
              <PieChart>
                <Pie data={categoryChart} cx="50%" cy="50%" outerRadius={100} dataKey="value" label={({ name, percent }) => `${(percent * 100).toFixed(0)}%`} labelLine={false}>
                  {categoryChart.map((e, i) => <Cell key={i} fill={e.color} />)}
                </Pie>
                <Tooltip formatter={(v) => formatCurrency(v, currency)} contentStyle={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '8px', color: 'var(--text-primary)' }} />
                <Legend formatter={(v) => <span style={{ color: 'var(--text-secondary)', fontSize: '12px' }}>{v}</span>} />
              </PieChart>
            </ResponsiveContainer>
          ) : (
            <div style={{ textAlign: 'center', padding: '60px 0', color: 'var(--text-muted)' }}>
              <div style={{ fontSize: '40px' }}>≡ƒôè</div><p>No expense data for {year}</p>
            </div>
          )}
        </motion.div>

        {/* Subscription bar */}
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}
          className="glass-card" style={{ padding: '24px' }}>
          <h3 style={{ fontSize: '16px', fontWeight: '700', marginBottom: '20px' }}>Subscription Cost by Category</h3>
          {subByCategory.length > 0 ? (
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={subByCategory} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" horizontal={false} />
                <XAxis type="number" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} tickFormatter={v => `Γé╣${v}`} />
                <YAxis type="category" dataKey="name" tick={{ fill: 'var(--text-secondary)', fontSize: 12 }} axisLine={false} tickLine={false} width={90} />
                <Tooltip formatter={v => formatCurrency(v, currency)} contentStyle={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '8px', color: 'var(--text-primary)' }} />
                <Bar dataKey="value" name="Monthly Cost" fill="#8b5cf6" radius={[0, 6, 6, 0]} />
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div style={{ textAlign: 'center', padding: '60px 0', color: 'var(--text-muted)' }}>
              <div style={{ fontSize: '40px' }}>≡ƒô▒</div><p>No active subscriptions</p>
            </div>
          )}
        </motion.div>
      </div>

      {/* Top categories table */}
      {categoryChart.length > 0 && (
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.5 }}
          className="glass-card" style={{ padding: '24px' }}>
          <h3 style={{ fontSize: '16px', fontWeight: '700', marginBottom: '20px' }}>Spending Breakdown</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {categoryChart.map((cat, i) => (
              <div key={cat.name} style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <div style={{ width: '24px', fontSize: '16px', textAlign: 'center' }}>{cat.icon}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                    <span style={{ fontSize: '13px', fontWeight: '600' }}>{cat.name}</span>
                    <span style={{ fontSize: '13px', fontWeight: '700' }}>{formatCurrency(cat.value, currency)}</span>
                  </div>
                  <div style={{ height: '6px', background: 'var(--bg-secondary)', borderRadius: '3px', overflow: 'hidden' }}>
                    <motion.div initial={{ width: 0 }} animate={{ width: `${(cat.value / totalSpend) * 100}%` }} transition={{ duration: 0.8, delay: i * 0.05 }}
                      style={{ height: '100%', background: cat.color, borderRadius: '3px' }} />
                  </div>
                  <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: '2px' }}>{((cat.value / totalSpend) * 100).toFixed(1)}% of total</div>
                </div>
              </div>
            ))}
          </div>
        </motion.div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Eye, EyeOff, Mail, Lock, User, TrendingUp, Sparkles } from 'lucide-react';
import useAuthStore from '../store/authStore';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const floatingCards = [
  { icon: '≡ƒÆ│', label: 'Smart Budgets', top: '15%', left: '5%', delay: 0 },
  { icon: '≡ƒôê', label: '+24% Growth', top: '70%', left: '3%', delay: 0.4 },
  { icon: '≡ƒöö', label: 'Bill Reminders', top: '30%', right: '4%', delay: 0.8 },
  { icon: 'ΓÜí', label: 'Instant Insights', top: '65%', right: '5%', delay: 1.2 },
];

const FloatingCard = ({ card }) => (
  <motion.div
    initial={{ opacity: 0, y: 20 }}
    animate={{ opacity: 1, y: 0, transition: { delay: card.delay, duration: 0.6 } }}
    style={{ top: card.top, left: card.left, right: card.right }}
    className="absolute hidden lg:flex items-center gap-2 glass-card px-4 py-2 text-sm font-medium"
    // style={{
    //   top: card.top, left: card.left, right: card.right,
    //   background: 'rgba(22,22,31,0.9)',
    //   border: '1px solid rgba(99,102,241,0.2)',
    //   borderRadius: '12px',
    //   padding: '10px 16px',
    //   display: 'flex',
    //   alignItems: 'center',
    //   gap: '8px',
    //   fontSize: '13px',
    //   fontWeight: '500',
    //   color: 'var(--text-primary)',
    //   backdropFilter: 'blur(10px)',
    // }}
  >
    <span>{card.icon}</span>
    <span>{card.label}</span>
  </motion.div>
);

export default function AuthPage() {
  const [mode, setMode] = useState('login');
  const [showPass, setShowPass] = useState(false);
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const { login, register, isLoading } = useAuthStore();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    let result;
    if (mode === 'login') {
      result = await login(form.email, form.password);
    } else {
      if (!form.name) return toast.error('Name is required');
      result = await register(form.name, form.email, form.password);
    }
    if (result.success) {
      toast.success(mode === 'login' ? 'Welcome back! ≡ƒæï' : 'Account created! ≡ƒÄë');
      navigate('/');
    } else {
      toast.error(result.message);
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg-primary)', display: 'flex', alignItems: 'stretch', position: 'relative', overflow: 'hidden' }}>
      <div className="animated-bg" />

      {/* Left Panel */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', padding: '60px', position: 'relative', overflow: 'hidden' }} className="hidden lg:flex">
        <div style={{ position: 'absolute', width: '600px', height: '600px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(99,102,241,0.12) 0%, transparent 70%)', top: '50%', left: '50%', transform: 'translate(-50%,-50%)' }} />
        
        {floatingCards.map((card, i) => (
          <FloatingCard key={i} card={card} />
        ))}

        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          style={{ textAlign: 'center', zIndex: 1 }}
        >
          <div style={{ fontSize: '64px', marginBottom: '24px' }}>≡ƒÆ╣</div>
          <h1 className="gradient-text" style={{ fontSize: '42px', fontWeight: '800', fontFamily: 'Space Grotesk', lineHeight: '1.2', marginBottom: '16px' }}>
            FinTracker Pro
          </h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: '18px', maxWidth: '360px', lineHeight: '1.6' }}>
            Your intelligent companion for financial freedom and subscription mastery.
          </p>

          {/* Stats row */}
          <div style={{ display: 'flex', gap: '24px', marginTop: '48px', justifyContent: 'center' }}>
            {[{ val: 'Γé╣2L+', label: 'Tracked Monthly' }, { val: '500+', label: 'Active Users' }, { val: '99.9%', label: 'Uptime' }].map((s, i) => (
