      </motion.div>

      {/* Profile Card */}
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}
        className="glass-card" style={{ padding: '28px', marginBottom: '16px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '24px' }}>
          <div style={{ width: '64px', height: '64px', borderRadius: '50%', background: 'linear-gradient(135deg, #6366f1, #ec4899)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '24px', fontWeight: '800', color: 'white' }}>
            {initials}
          </div>
          <div>
            <div style={{ fontSize: '18px', fontWeight: '700', marginBottom: '2px' }}>{user?.name}</div>
            <div style={{ fontSize: '14px', color: 'var(--text-muted)' }}>{user?.email}</div>
            <span className="badge badge-purple" style={{ marginTop: '6px', fontSize: '11px' }}>Premium Member</span>
          </div>
        </div>

        <form onSubmit={handleSave} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          <div>
            <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>
              <User size={14} style={{ display: 'inline', marginRight: '6px' }} />Full Name
            </label>
            <input className="input-field" value={profile.name} onChange={e => setProfile({ ...profile, name: e.target.value })} />
          </div>

          <div>
            <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>
              <DollarSign size={14} style={{ display: 'inline', marginRight: '6px' }} />Currency
            </label>
            <select className="input-field" value={profile.currency} onChange={e => setProfile({ ...profile, currency: e.target.value })}>
              {CURRENCIES.map(c => <option key={c.code} value={c.code}>{c.label}</option>)}
            </select>
          </div>

          <div>
            <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>
              Monthly Budget (optional)
            </label>
            <input className="input-field" type="number" min="0" placeholder="Set a monthly budget limit" value={profile.monthlyBudget} onChange={e => setProfile({ ...profile, monthlyBudget: e.target.value })} />
            {profile.monthlyBudget > 0 && (
              <p style={{ fontSize: '12px', color: 'var(--accent-light)', marginTop: '4px' }}>
                Alerts will trigger when you exceed {new Intl.NumberFormat('en-IN', { style: 'currency', currency: profile.currency }).format(profile.monthlyBudget)}
              </p>
            )}
          </div>

          <motion.button type="submit" className="btn-primary" disabled={saving} whileTap={{ scale: 0.98 }}
            style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', width: '100%' }}>
            {saving ? <span className="spinner" style={{ width: '16px', height: '16px', borderWidth: '2px' }} /> : <><Save size={15} /> Save Changes</>}
          </motion.button>
        </form>
      </motion.div>

      {/* Appearance */}
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}
        className="glass-card" style={{ padding: '24px', marginBottom: '16px' }}>
        <h3 style={{ fontSize: '16px', fontWeight: '700', marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          {theme === 'dark' ? <Moon size={18} /> : <Sun size={18} />} Appearance
        </h3>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontSize: '14px', fontWeight: '600', marginBottom: '4px' }}>Theme Mode</div>
            <div style={{ fontSize: '13px', color: 'var(--text-muted)' }}>Currently using {theme} mode</div>
          </div>
          <button onClick={toggleTheme} style={{
            display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 20px',
            borderRadius: '10px', border: '1px solid var(--border)', cursor: 'pointer',
            background: 'var(--bg-secondary)', color: 'var(--text-primary)', fontSize: '14px', fontWeight: '500'
          }}>
            {theme === 'dark' ? <><Sun size={16} /> Light Mode</> : <><Moon size={16} /> Dark Mode</>}
          </button>
        </div>
      </motion.div>

      {/* Account Info */}
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }}
        className="glass-card" style={{ padding: '24px' }}>
        <h3 style={{ fontSize: '16px', fontWeight: '700', marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <Shield size={18} /> Account Security
        </h3>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {[
            { label: 'Email Address', value: user?.email, icon: '≡ƒôº' },
            { label: 'Member Since', value: new Date(user?.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' }), icon: '≡ƒôà' },
            { label: 'Account Status', value: 'Active & Verified', icon: 'Γ£à' },
          ].map((item, i) => (
            <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '12px', background: 'var(--bg-secondary)', borderRadius: '10px' }}>
              <span style={{ fontSize: '13px', color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', gap: '8px' }}>{item.icon} {item.label}</span>
              <span style={{ fontSize: '13px', fontWeight: '600' }}>{item.value}</span>
            </div>
          ))}
        </div>
      </motion.div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Edit2, Trash2, X, Pause, Play, Bell } from 'lucide-react';
import api from '../lib/api';
import useAuthStore from '../store/authStore';
import { formatCurrency, formatDate, getDaysUntil, getMonthlyEquivalent } from '../utils/helpers';
import toast from 'react-hot-toast';

const SUB_CATEGORIES = ['Streaming', 'Music', 'Gaming', 'Productivity', 'Cloud Storage', 'Health & Fitness', 'News & Media', 'Education', 'Software', 'Other'];
const BILLING_CYCLES = ['weekly', 'monthly', 'quarterly', 'yearly'];

const POPULAR_SUBS = [
  { name: 'Netflix', logo: '≡ƒÄ¼', color: '#e50914', amount: 649 },
  { name: 'Spotify', logo: '≡ƒÄ╡', color: '#1db954', amount: 119 },
  { name: 'Amazon Prime', logo: '≡ƒôª', color: '#ff9900', amount: 299 },
  { name: 'Disney+', logo: '≡ƒÅ░', color: '#113ccf', amount: 299 },
  { name: 'YouTube Premium', logo: 'Γû╢∩╕Å', color: '#ff0000', amount: 139 },
  { name: 'Apple Music', logo: '≡ƒÄ╢', color: '#fc3c44', amount: 99 },
];

const emptyForm = {
  name: '', amount: '', billingCycle: 'monthly', category: 'Streaming', color: '#6366f1',
  logo: '', startDate: new Date().toISOString().split('T')[0],
  nextBillingDate: new Date().toISOString().split('T')[0], notes: '', reminderDays: 3,
};

function SubModal({ onClose, onSave, initial }) {
  const [form, setForm] = useState(initial ? {
    ...initial,
    startDate: new Date(initial.startDate).toISOString().split('T')[0],
    nextBillingDate: new Date(initial.nextBillingDate).toISOString().split('T')[0],
  } : emptyForm);
  const [saving, setSaving] = useState(false);

  const applyPreset = (sub) => {
    setForm(f => ({ ...f, name: sub.name, logo: sub.logo, color: sub.color, amount: sub.amount, category: 'Streaming' }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      if (initial?._id) {
        await api.put(`/subscriptions/${initial._id}`, form);
        toast.success('Subscription updated!');
      } else {
        await api.post('/subscriptions', form);
        toast.success('Subscription added!');
      }
      onSave();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Something went wrong');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }}
        style={{ background: 'var(--bg-card)', borderRadius: '20px', padding: '28px', width: '100%', maxWidth: '520px', border: '1px solid var(--border)', maxHeight: '90vh', overflowY: 'auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h2 style={{ fontSize: '20px', fontWeight: '700', fontFamily: 'Space Grotesk' }}>{initial?._id ? 'Γ£Å∩╕Å Edit Subscription' : 'Γ₧ò Add Subscription'}</h2>
          <button onClick={onClose} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)' }}><X size={20} /></button>
        </div>

        {/* Quick presets */}
        {!initial?._id && (
          <div style={{ marginBottom: '20px' }}>
            <p style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '10px', fontWeight: '600', textTransform: 'uppercase' }}>Popular Services</p>
            <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
              {POPULAR_SUBS.map(sub => (
                <button key={sub.name} onClick={() => applyPreset(sub)}
                  style={{ padding: '6px 12px', borderRadius: '8px', border: '1px solid var(--border)', background: 'var(--bg-secondary)', cursor: 'pointer', fontSize: '13px', display: 'flex', alignItems: 'center', gap: '6px', color: 'var(--text-primary)', transition: 'all 0.2s' }}
                  onMouseEnter={e => e.target.style.borderColor = sub.color}
                  onMouseLeave={e => e.target.style.borderColor = 'var(--border)'}>
                  {sub.logo} {sub.name}
                </button>
              ))}
            </div>
          </div>
        )}

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 60px', gap: '10px', alignItems: 'end' }}>
            <div>
              <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>Service Name *</label>
              <input className="input-field" placeholder="e.g. Netflix" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} required />
            </div>
            <div>
              <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>Icon</label>
              <input className="input-field" placeholder="≡ƒÄ¼" value={form.logo} onChange={e => setForm({ ...form, logo: e.target.value })} style={{ textAlign: 'center', fontSize: '20px' }} />
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
            <div>
              <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>Amount (Γé╣) *</label>
              <input className="input-field" type="number" placeholder="0.00" min="0" step="0.01" value={form.amount} onChange={e => setForm({ ...form, amount: e.target.value })} required />
            </div>
            <div>
              <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>Billing Cycle</label>
              <select className="input-field" value={form.billingCycle} onChange={e => setForm({ ...form, billingCycle: e.target.value })}>
                {BILLING_CYCLES.map(c => <option key={c} value={c}>{c.charAt(0).toUpperCase() + c.slice(1)}</option>)}
              </select>
            </div>
          </div>

